mapper.select:
SELECT round_no, member_no, pred_num, hit_yn, submit_at, create_ts, update_ts
FROM MEM_PRED_NUM
WHERE round_no  = #{roundNo}
  AND member_no = #{memberNo}

SELECT ra.ranking, COALESCE(m.nickname, m.user_id) AS nickname, p.pred_num AS predNum, p.hit_yn, p.submit_at FROM MEM_PRED_NUM p JOIN MEM_JOIN_INFO m ON m.member_no = p.member_no LEFT JOIN MEM_RANK_ALL ra ON ra.member_no = p.member_no AND ra.round_no = #{roundNo} - 1 WHERE p.round_no = #{roundNo}
ORDER BY (ra.ranking IS NULL) DESC, ra.ranking DESC, p.submit_at ASC
ORDER BY (ra.ranking IS NULL) ASC, ra.ranking ASC, p.submit_at ASC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
  FROM MEM_PRED_NUM p
 WHERE p.round_no = #{roundNo}
